       var date = end.getDate();
       var hr = end.getHours();
       var min = end.getMinutes();
       var sec = end.getSeconds();
       if (month < 10) {
         month = "0" + month;
       }
       if (date < 10) {
         date = "0" + date;
       }
       if (hr < 10) {
         hr = "0" + hr;
       }
       if (min < 10) {
         min = "0" + min;
       }
       if (sec < 10) {
         sec = "0" + sec;
       }
       var endDate = end.getFullYear() + "-" + month + "-" + date + " " + hr + ":" + min + ":" + sec;
       this.end = endDate;
